DELETE FROM work_days;

-- حذف جميع العمال
DELETE FROM workers;

-- حذف جميع نوبات المجموعات
DELETE FROM group_shifts;

-- حذف جميع المجموعات
DELETE FROM groups;

-- حذف جميع مراكز التكلفة
DELETE FROM cost_centers;

-- حذف جميع الأعلام التشغيلية
DELETE FROM operational_flags;

-- التحقق من عدد السجلات المتبقية
SELECT 
  (SELECT COUNT(*) FROM workers) as workers_count,
  (SELECT COUNT(*) FROM groups) as groups_count,
  (SELECT COUNT(*) FROM cost_centers) as cost_centers_count,
  (SELECT COUNT(*) FROM worker_daily_finance) as daily_finance_count,
  (SELECT COUNT(*) FROM payroll_batches) as batches_count;

